#include<bits/stdc++.h>
using namespace std;
int s[200010];
struct node
{
    int l,r;
    bool operator<(const node&b)const
    {
        return l<b.l;
    }
}a[200010];
long long dp[100010];
const long long mod=1e9+7;
long long fastpow(long long x,long long y)
{
    long long ans=1;
    while(y)
    {
        if(y%2==1)
        {
            ans=ans*x%mod;
        }
        x=x*x%mod;
        y/=2;
    }
    return ans;
}
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d",&a[i].l,&a[i].r);
        s[a[i].r]++;
    }
    sort(a+1,a+1+n);
    for(int i=1;i<=n*2;i++)
    {
        s[i]+=s[i-1];
    }
    for(int i=1;i<=n;i++)
    {
        dp[i]=(dp[i-1]*2+fastpow(2,s[a[i].l]))%mod;
    }
    printf("%lld",dp[n]);
    return 0;
}
